/** @param {string} hex #rrggbb */
function hexToRgb(hex) {
  const h = hex.replace('#', '');
  return {
    r: parseInt(h.slice(0, 2), 16),
    g: parseInt(h.slice(2, 4), 16),
    b: parseInt(h.slice(4, 6), 16),
  };
}

function rgbToHex(r, g, b) {
  const c = (n) => Math.max(0, Math.min(255, Math.round(n))).toString(16).padStart(2, '0');
  return `#${c(r)}${c(g)}${c(b)}`;
}

/** Mix two hex colors. t=0 -> a, t=1 -> b. */
function mix(a, b, t) {
  const A = hexToRgb(a), B = hexToRgb(b);
  return rgbToHex(A.r + (B.r - A.r) * t, A.g + (B.g - A.g) * t, A.b + (B.b - A.b) * t);
}

/** Darken toward a warm shadow (not pure black -> avoids muddy flat shading). */
function shade(hex, amount = 0.12) {
  return mix(hex, '#3a2b2b', amount);
}

/** Lighten toward a soft highlight. */
function tint(hex, amount = 0.12) {
  return mix(hex, '#fffaf4', amount);
}

/** Reduce saturation toward the colour's own grey. sat=1 keeps it, 0 = grey. */
function desaturate(hex, sat = 1) {
  const { r, g, b } = hexToRgb(hex);
  const lum = 0.3 * r + 0.59 * g + 0.11 * b;
  const s = Math.max(0, Math.min(1, sat));
  return rgbToHex(lum + (r - lum) * s, lum + (g - lum) * s, lum + (b - lum) * s);
}


// ===== src/genome/rng.js =====
// Seeded deterministic RNG so a given seed always yields the same face.
function hashSeed(str) {
  let h = 1779033703 ^ str.length;
  for (let i = 0; i < str.length; i++) {
    h = Math.imul(h ^ str.charCodeAt(i), 3432918353);
    h = (h << 13) | (h >>> 19);
  }
  return h >>> 0;
}
function mulberry32(seed) {
  let a = seed >>> 0;
  return function () {
    a |= 0;
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
function makeRng(seedStr) {
  const rng = mulberry32(hashSeed(String(seedStr)));
  return {
    next: rng,
    range: (lo, hi) => lo + (hi - lo) * rng(),
    int: (lo, hi) => Math.floor(lo + (hi - lo + 1) * rng()),
    pick: (arr) => arr[Math.floor(rng() * arr.length)],
    // weighted pick: items = [[value, weight], ...]
    weighted: (items) => {
      const total = items.reduce((a, [, w]) => a + w, 0);
      let r = rng() * total;
      for (const [v, w] of items) {
        if ((r -= w) <= 0) return v;
      }
      return items[items.length - 1][0];
    },
    bool: (p = 0.5) => rng() < p,
  };
}


